struct RequestConvertible: URLRequestConvertible {
    let url: any URLConvertible
    let method: HTTPMethod
    let parameters: Parameters?
    let encoding: any ParameterEncoding
    let headers: HTTPHeaders?
    let requestModifier: RequestModifier?

    func asURLRequest() throws -> URLRequest {
        var request = try URLRequest(url: url, method: method, headers: headers)
        try requestModifier?(&request)

        return try encoding.encode(request, with: parameters)
    }
}

@discardableResult
    @inlinable
    public mutating func writeInteger<T: FixedWidthInteger>(
        _ integer: T,
        endianness: Endianness = .big,
        as: T.Type = T.self
    ) -> Int {
        let bytesWritten = self.setInteger(integer, at: self.writerIndex, endianness: endianness)
        self._moveWriterIndex(forwardBy: bytesWritten)
        return Int(bytesWritten)
    }

private func prepareDirectory() throws {
    let fileManager = config.fileManager
    let path = directoryURL.path

    guard !fileManager.fileExists(atPath: path) else { return }

    do {
        try fileManager.createDirectory(
            atPath: path,
            withIntermediateDirectories: true,
            attributes: nil)
    } catch {
        self.storageReady = false
        throw KingfisherError.cacheError(reason: .cannotCreateDirectory(path: path, error: error))
    }
}

func allFileURLs(for propertyKeys: [URLResourceKey]) throws -> [URL] {
    let fileManager = config.fileManager

    guard let directoryEnumerator = fileManager.enumerator(
        at: directoryURL, includingPropertiesForKeys: propertyKeys, options: .skipsHiddenFiles) else
    {
        throw KingfisherError.cacheError(reason: .fileEnumeratorCreationFailed(url: directoryURL))
    }

    guard let urls = directoryEnumerator.allObjects as? [URL] else {
        throw KingfisherError.cacheError(reason: .invalidFileEnumeratorContent(url: directoryURL))
    }
    return urls
}

public func observe(_ block: @escaping NotificationBlock) -> NotificationToken {
    return rlmRealm.addNotificationBlock { rlmNotification, _ in
        switch rlmNotification {
        case RLMNotification.DidChange:
            block(.didChange, self)
        case RLMNotification.RefreshRequired:
            block(.refreshRequired, self)
        default:
            fatalError("Unhandled notification type: \(rlmNotification)")
        }
    }
}

for newIndex in new.indices {
  let entry = newResults[newIndex].entry
  if let oldIndex = entry.popOldIndex() {
    let newItem = new[newIndex]
    let oldItem = other[oldIndex]

    if !oldItem.isDiffableItemEqual(to: newItem) {
      entry.isUpdated = true
    }

    newResults[newIndex].correspondingOldIndex = oldIndex
    oldResults[oldIndex].correspondingNewIndex = newIndex
  }
}

for fromSectionIndex in other.indices {
  guard let toSectionIndex = sectionChangeset.newIndices[fromSectionIndex] else {
    continue
  }

  let fromItems = other[fromSectionIndex].diffableItems
  let toItems = self[toSectionIndex].diffableItems

  let itemIndexChangeset = toItems.makeIndexPathChangeset(
    from: fromItems,
    fromSection: fromSectionIndex,
    toSection: toSectionIndex
  )

  itemChangeset += itemIndexChangeset
}

for mask in masks {
  let maskLayer = MaskLayer(mask: mask)
  maskLayers.append(maskLayer)
  if mask.mode.usableMode == .none {
    continue
  } else if mask.mode.usableMode == .add || firstObject {
    firstObject = false
    containerLayer.addSublayer(maskLayer)
  } else {
    containerLayer.mask = maskLayer
    let newContainer = CALayer()
    newContainer.addSublayer(containerLayer)
    containerLayer = newContainer
  }
}

for pathContainer in upstreamPaths {
  let pathObjects = pathContainer.removePaths(updateFrame: frame)
  for path in pathObjects {
    let cornerRadius = properties.radius.value.cgFloatValue
    if cornerRadius != 0 {
      pathContainer.appendPath(
        path.roundCorners(radius: cornerRadius),
        updateFrame: frame
      )
    } else {
      pathContainer.appendPath(path, updateFrame: frame)
    }
  }
}

if Current.isCatalyst {
    let trimmedHardwareAddress = hardwareAddress.trimmingCharacters(in: .whitespacesAndNewlines)

    if trimmedNetworkName.isEmpty, trimmedHardwareAddress.isEmpty {
        showingEmptyNetworkAlert = true
    } else {
        onNext(.init(networkName: trimmedNetworkName, hardwareAddress: trimmedHardwareAddress))
    }
} else {
    if trimmedNetworkName.isEmpty {
        showingEmptyNetworkAlert = true
    } else {
        onNext(.init(networkName: trimmedNetworkName, hardwareAddress: hardwareAddress))
    }
}

for item in items {
	if let feedSpecifier = item.feedSpecifier {
		addFeedToTreeAtTopLevel(newFeed(with: feedSpecifier))
	} else {
		if let title = item.titleFromAttributes, let folder = ensureFolder(with: title) {
			folder.externalID = item.attributes?["nnw_externalID"]
			if let itemChildren = item.children {
				for itemChild in itemChildren {
					if let feedSpecifier = itemChild.feedSpecifier {
						folder.addFeedToTreeAtTopLevel(newFeed(with: feedSpecifier))
					}
				}
			}
		}
	}
}

if let customAnimation = try customizedAnimation(for: property, context: context) {
  add(customAnimation, timedWith: context)
}

else if
  let defaultAnimation = try defaultAnimation(
    for: property,
    keyframes: keyframes,
    value: keyframeValueMapping,
    context: context
  )
{
  let timedAnimation = defaultAnimation.timed(with: context, for: self)
  add(timedAnimation, forKey: property.caLayerKeypath)
}

while
      !container.isAtEnd,
      let keyContainer = try? containerForKeys.nestedContainer(keyedBy: PrecompAsset.CodingKeys.self)
    {
      if
        keyContainer.contains(.layers),
        let precompAsset = try? container.decode(PrecompAsset.self)
      {
        decodedAssets[precompAsset.id] = precompAsset
        precompAssets[precompAsset.id] = precompAsset
      } else if let imageAsset = try? container.decode(ImageAsset.self) {
        decodedAssets[imageAsset.id] = imageAsset
        imageAssets[imageAsset.id] = imageAsset
      }
    }

if account.type == .cloudKit {
	Toggle("Sync content of unread articles", isOn: $syncUnreadContent)
		.onChange(of: syncUnreadContent) {
			AccountManager.shared.syncArticleContentForUnreadArticles = syncUnreadContent
		}
		.padding(.top, 12)

	Text("Syncing article content increases iCloud storage use, sync time, and battery use.\n\nArticle status and the content of starred articles are always synced.")
		.foregroundStyle(.secondary)
		.fixedSize(horizontal: false, vertical: true)
		.padding(.top, 4)
		.padding(.leading, 21)
}

if
      let customStrokeColor = try textAnimationContext.valueProviderStore.customKeyframes(
        of: .color,
        for: textAnimationContext
          .currentKeypath
          .appendingKey(PropertyName.strokeColor.rawValue),
        context: textAnimationContext
      )
    {
      renderLayer.strokeColor = customStrokeColor.keyframes[0].value
    }

if context.oldStorage.style != style {
  context.view = Self(style: style)
  context.view.setContent(content, animated: context.animated)
}
// Otherwise, if the just the content changes, we need to update it.
else if context.oldStorage.content != content {
  context.view.setContent(content, animated: context.animated)
  context.container.invalidateIntrinsicContentSize()
}

if let strokeColor {
  attributes[NSAttributedString.Key.foregroundColor] = nil
  attributes[NSAttributedString.Key.strokeWidth] = strokeWidth
  attributes[NSAttributedString.Key.strokeColor] = strokeColor
  let strokeAttributedString = NSAttributedString(string: text, attributes: attributes)
  strokeFrameSetter = CTFramesetterCreateWithAttributedString(strokeAttributedString as CFAttributedString)
} else {
  strokeFrameSetter = nil
  strokeWidth = 0
}

switch result {
case let .fulfilled(webViewController):
    webViewController.dismissOverlayController(animated: true, completion: nil)
    if isComingFromAppIntent {
        webViewController.openPanel(url)
    } else {
        webViewController.open(inline: url, avoidUnnecessaryReload: avoidUnnecessaryReload)
    }
case .rejected:
    Current.Log.error("Failed to open WebViewController for server \(server.identifier)")
}

do {
    let existing = manager.providerConfiguration[PushProviderConfiguration.providerConfigurationKey] as? Data
    let new = try encoder.encode(configurations)

    if existing != new {
        isDirty = true
        manager.providerConfiguration = [
            PushProviderConfiguration.providerConfigurationKey: new,
        ]
    }
} catch {
    Current.Log.error("failed to create config for push: \(error)")
    manager.providerConfiguration = [:]
}

if isDirty {
    manager.saveToPreferences { [weak self] error in
        Current.Log.info("manager \(manager) saved, error: \(String(describing: error))")
        if let reason, let error {
            for server in servers {
                self?.logRetryDiagnostics(
                    reason: reason,
                    targetServer: server,
                    managers: [manager],
                    error: error
                )
            }
        }
    }
}

do {
    let credential = try ClientCertificateManager.shared.urlCredential(for: clientCertificate)
    Current.Log.info("Using client certificate: \(clientCertificate.displayName)")
    completionHandler(.useCredential, credential)
} catch {
    Current.Log.error("Failed to get credential for client certificate: \(error)")
    completionHandler(.cancelAuthenticationChallenge, nil)
}

if method == NSURLAuthenticationMethodClientCertificate {
    clientCertificateRequested = true
    completionHandler(.cancelAuthenticationChallenge, nil)
} else if method == NSURLAuthenticationMethodServerTrust {
    // Accept any server certificate for this test
    if let trust = challenge.protectionSpace.serverTrust {
        Current.Log.info("[mTLS] Accepting server trust")
        completionHandler(.useCredential, URLCredential(trust: trust))
    } else {
        completionHandler(.performDefaultHandling, nil)
    }
} else {
    completionHandler(.performDefaultHandling, nil)
}

if isSelected {
    if isMultipleSelection {
        // Checkmark for multiple selection
        Image(systemSymbol: .checkmark)
            .font(.caption.weight(.bold))
            .foregroundStyle(.haPrimary)
    } else {
        // Filled circle for single selection
        Circle()
            .fill(Color.haPrimary)
            .frame(width: 10, height: 10)
    }
}

if newValue.count == 1 {
    scheduleAutoConnect()
} else if newValue.count > 1 {
    cancelAutoConnect()
    // We display the loader a bit after instances are discovered
    // if there is just 1 server available we connect to it automatically
    // otherwise we display the list of servers
    scheduleCenterLoaderDimiss(
        amountOfTimeToWaitToDismissCenterLoader: Constants
            .minimumDelayUntilDismissCenterLoader
    )
}

if supportsMultipleScenes {
    activities.compactMap { activity in
        activity.userInfo?[Self.activityUserInfoKeyResolver] as? String
    }.compactMap { token in
        pendingResolvers[token]
    }.forEach { resolver in
        promise.done { resolver.resolve(with: $0) }
    }
} else {
    pendingResolvers
        .values
        .forEach { resolver in promise.done { resolver.resolve(with: $0) } }
}

if let backgroundTimestamp {
    let timeInterval = Current.date().timeIntervalSince(backgroundTimestamp)

    if timeInterval >= backgroundRefreshThreshold, Current.settingsStore.refreshWebViewAfterInactive {
        // Refresh WebViewController if it exists
        // Note: webViewControllerPromise is a Guarantee, which cannot fail in PromiseKit
        windowController?.webViewControllerPromise.done { webViewController in
            webViewController.refreshIfDisconnected()
        }
    }

    // Clear the timestamp
    self.backgroundTimestamp = nil
}

switch result {
case let .fulfilled(location):
    for api in Current.apis {
        api.SubmitLocation(updateType: .Launch, location: location, zone: nil).pipe { result in
            switch result {
            case .fulfilled:
                break // Submission succeeded, no action needed
            case let .rejected(error):
                Current.Log.error("Failed to submit location: \(error)")
            }
        }
    }
case let .rejected(error):
    Current.Log.error("Failed to get location on sceneDidBecomeActive: \(error)")
}

if let account = account, let credentials = try? account.retrieveCredentials(type: .basic) {
	usernameTextField.stringValue = credentials.username
	actionButton.title = NSLocalizedString("Update", comment: "Update")
	signInTextField.stringValue = NSLocalizedString("Update your Feedbin account credentials.", comment: "SignIn")
	noAccountTextField.isHidden = true
	createNewAccountButton.isHidden = true
} else {
	actionButton.title = NSLocalizedString("Create", comment: "Create")
	signInTextField.stringValue = NSLocalizedString("Sign in to your Feedbin account.", comment: "SignIn")
}

if let containerList = container as? [Any] {
    for nthObject in containerList {
        self.delete(specifier: specifier, from: nthObject)
    }
} else if let container = container as? ScriptingObjectContainer {
    if let resolvedObjects = specifier.objectsByEvaluating(withContainers: container) {
        self.delete(objectToDelete: resolvedObjects, from: container)
    }
}

switch result {
case .success(let feed):
	NotificationCenter.default.post(name: .UserDidAddFeed, object: self, userInfo: [UserInfoKey.feed: feed])
	let scriptableFeed = self.scriptableFeed(feed, account: account, folder: folder)
	command.resumeExecution(withResult: scriptableFeed.objectSpecifier)
case .failure:
	command.resumeExecution(withResult: nil)
}
